import{_ as i,o as t,c as o,ak as r}from"./chunks/framework.Dx0ZwfXr.js";const u=JSON.parse('{"title":"SecurityConfiguration","description":"","frontmatter":{},"headers":[],"relativePath":"api/reference/royalapps-community-rdp-winforms-configuration-security-securityconfiguration.md","filePath":"api/reference/royalapps-community-rdp-winforms-configuration-security-securityconfiguration.md"}'),a={name:"api/reference/royalapps-community-rdp-winforms-configuration-security-securityconfiguration.md"};function n(s,e,c,l,d,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="securityconfiguration" tabindex="-1"><code>SecurityConfiguration</code> <a class="header-anchor" href="#securityconfiguration" aria-label="Permalink to “SecurityConfiguration”">​</a></h1><p>Security related settings for the remote desktop connection.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to “Type”">​</a></h2><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RoyalApps.Community.Rdp.WinForms.Configuration.Security.SecurityConfiguration</span></span></code></pre></div><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="authenticationlevel-authenticationlevel-↗" tabindex="-1"><code>AuthenticationLevel</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-connection-authenticationlevel">AuthenticationLevel</a>) <a class="api-member-external-link" href="https://learn.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings4-authenticationlevel" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#authenticationlevel-authenticationlevel-↗" aria-label="Permalink to “AuthenticationLevel (AuthenticationLevel) ↗”">​</a></h3><p>Specifies the authentication level to use for the connection.</p><h3 id="authenticationserviceclass-string" tabindex="-1"><code>AuthenticationServiceClass</code> (<code>string</code>?) <a class="header-anchor" href="#authenticationserviceclass-string" aria-label="Permalink to “AuthenticationServiceClass (string?)”">​</a></h3><p>Specifies the service principal name (SPN) service class used when authenticating to the target. The default service class for RDP is typically <code>TERMSRV</code>. This is primarily useful when connecting to endpoints that register a non-default SPN, such as Hyper-V VM console sessions. Support: embedded sessions only. This setting is not written into generated external <code>.rdp</code> files.</p><h3 id="connecttoadministerserver-bool-↗" tabindex="-1"><code>ConnectToAdministerServer</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings6-connecttoadministerserver" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#connecttoadministerserver-bool-↗" aria-label="Permalink to “ConnectToAdministerServer (bool) ↗”">​</a></h3><p>Retrieves or specifies whether the ActiveX control should attempt to connect to the server for administrative purposes.</p><h3 id="disablecredentialsdelegation-bool" tabindex="-1"><code>DisableCredentialsDelegation</code> (<code>bool</code>) <a class="header-anchor" href="#disablecredentialsdelegation-bool" aria-label="Permalink to “DisableCredentialsDelegation (bool)”">​</a></h3><p>Prevents the client from delegating credentials to the remote server. This is a building block used by Remote Credential Guard and Restricted Administration / Restricted Logon scenarios. Support: embedded sessions directly, external sessions through MsRdpEx-specific mapping when <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-external-externalsessionconfiguration">ExternalSessionConfiguration.UseMsRdpExHooks</a> is enabled.</p><h3 id="publicmode-bool-↗" tabindex="-1"><code>PublicMode</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings5-publicmode" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#publicmode-bool-↗" aria-label="Permalink to “PublicMode (bool) ↗”">​</a></h3><p>Sets or retrieves the configuration for public mode. Public mode prevents the client from caching user data to the local system.</p><h3 id="redirectedauthentication-bool" tabindex="-1"><code>RedirectedAuthentication</code> (<code>bool</code>) <a class="header-anchor" href="#redirectedauthentication-bool" aria-label="Permalink to “RedirectedAuthentication (bool)”">​</a></h3><p>Enables authentication redirection back to the local device. This is a building block used by Remote Credential Guard and typically requires <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-security-securityconfiguration">SecurityConfiguration.DisableCredentialsDelegation</a>. Support: embedded sessions directly, external sessions through MsRdpEx-specific mapping when <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-external-externalsessionconfiguration">ExternalSessionConfiguration.UseMsRdpExHooks</a> is enabled.</p><h3 id="remotecredentialguard-bool-↗" tabindex="-1"><code>RemoteCredentialGuard</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/security/identity-protection/remote-credential-guard" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#remotecredentialguard-bool-↗" aria-label="Permalink to “RemoteCredentialGuard (bool) ↗”">​</a></h3><p>Remote Credential Guard helps protect credentials over a Remote Desktop connection by redirecting Kerberos requests back to the device that initiated the connection. It also provides single sign-on for Remote Desktop sessions. When enabled, <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-security-securityconfiguration">SecurityConfiguration.RedirectedAuthentication</a> and <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-security-securityconfiguration">SecurityConfiguration.DisableCredentialsDelegation</a> are set to <code>true</code>.</p><h3 id="restrictedadminmode-bool-↗" tabindex="-1"><code>RestrictedAdminMode</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/archive/blogs/kfalde/restricted-admin-mode-for-rdp-in-windows-8-1-2012-r2" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#restrictedadminmode-bool-↗" aria-label="Permalink to “RestrictedAdminMode (bool) ↗”">​</a></h3><p>Connects to the remote PC or server in Restricted Administration mode. In this mode, credentials are not sent to the remote PC or server, which can help protect you if you connect to a compromised host. However, connections made from the remote PC might not be authenticated by other PCs and servers, which can affect app functionality and compatibility.</p><h3 id="restrictedlogon-bool" tabindex="-1"><code>RestrictedLogon</code> (<code>bool</code>) <a class="header-anchor" href="#restrictedlogon-bool" aria-label="Permalink to “RestrictedLogon (bool)”">​</a></h3><p>Enables restricted logon mode. This is a building block used by Restricted Administration mode and typically requires <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-security-securityconfiguration">SecurityConfiguration.DisableCredentialsDelegation</a>. Support: embedded sessions directly, external sessions through MsRdpEx-specific mapping when <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-external-externalsessionconfiguration">ExternalSessionConfiguration.UseMsRdpExHooks</a> is enabled.</p><p><a href="./../">Back to API index</a></p>',24)])])}const m=i(a,[["render",n]]);export{u as __pageData,m as default};
